firestore.rules:
service cloud.firestore {
  match /databases/{database}/documents {
    // Users collection (platform users, including super admins)
    match /users/{userId} {
      allow read: if request.auth != null;
      allow create: if request.auth != null && request.resource.data.role == 'super-admin';
      allow update: if request.auth != null && request.auth.uid == userId;
    }

    // System configuration
    match /system_config/{document=**} {
      allow read, write: if request.auth != null;
    }

    // Roles configuration
    match /roles/{document=**} {
      allow read, write: if request.auth != null;
    }

    // Publicly readable published clinics
    match /procarenepal_clinics/{clinicId} {
      allow read: if true;
      // Writes are handled elsewhere (admin / clinic dashboards)
      allow write: if false;
    }

    // Patient users (for authentication context)
    match /patient_users/{patientId} {
      allow read, write: if request.auth != null && request.auth.uid == patientId;
    }

    // Clinic reviews collection
    // One logical review per (clinicId, patientUid). Enforced at app layer; rules enforce ownership and sane values.
    match /clinic_reviews/{reviewId} {
      allow read: if true;

      function isSignedIn() {
        return request.auth != null;
      }

      function isOwner() {
        return isSignedIn() && request.auth.uid == resource.data.patientUid;
      }

      function isNewOwner() {
        return isSignedIn() && request.auth.uid == request.resource.data.patientUid;
      }

      function validRating() {
        return request.resource.data.rating is int &&
               request.resource.data.rating >= 1 &&
               request.resource.data.rating <= 5;
      }

      function validComment() {
        return !('comment' in request.resource.data) ||
               (request.resource.data.comment is string &&
                request.resource.data.comment.size() <= 2000);
      }

      // Create: authenticated patients only, with sane rating/comment values.
      allow create: if isNewOwner()
        && request.resource.data.clinicId is string
        && validRating()
        && validComment();

      // Update: only the owner can update, and they cannot change clinicId or patientUid.
      allow update: if isOwner()
        && request.resource.data.clinicId == resource.data.clinicId
        && request.resource.data.patientUid == resource.data.patientUid
        && validRating()
        && validComment();

      // Delete: only owner can soft/hard delete.
      allow delete: if isOwner();
    }

    // Default deny rule
    match /{document=**} {
      allow read, write: if false;
    }
  }
}
